head.script:
// 전역 변수
scwin.memJson = $c.data.getMemInfo(); // 세션 정보를 가지고 온다.

scwin.onpageload = function() {
    ed_status.hide();
	const codeOptions = [
        { grpCd : "EQ026", compID : "lc_buyCls,gr_eq420:buyClsCd" },
        { grpCd : "EQ902", compID : "gr_eq420:stsCd" }
    ];
    $c.data.setCommonCode(codeOptions);

    const param= [
        {
            method: "getLuxeComboData",
            param1: "PsCommonEBC",
            param2: "retriveHomeClsList",
            compID: "lc_homeClsCd"
        },
        {
            method: "getLuxeComboData",
            param1: "PsCommonEBC",
            param2: "retrievePartBuyStatus",
            compID: "acb_stsCd"
        }
    ];
    $c.data.setGauceUtil(param);
};

//-------------------------------------------------------------------------
// UDC 로딩 완료 후
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    scwin.f_defaultValue();
    ica_dtFrom.setValue($c.date.getServerDateTime("yyyyMM")+"01");
    ica_dtTo.setValue($c.date.getServerDateTime("yyyyMMdd"));
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_defaultValue = function() {
    //cfDisableObjects와 비슷한 형태로, 오브젝트의 값을 초기화시킨다.
    $c.gus.cfInitObjects([ed_clntNo, ed_clntNm]);

    $c.gus.cfDisableObjects([btn_detail]);

    acb_inDtCls.setSelectedIndex(0);

    lc_homeClsCd.setValue(scwin.memJson.eqHomeClsCd);   //정비소속구분코드

    if (scwin.memJson.eqHomeClsCd === "null") {
        lc_homeClsCd.setSelectedIndex(0);
    }

    scwin.f_RetrieveFixWrkPl(lc_homeClsCd.getValue());

    lc_homeClsCd.focus();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    // 필수입력항목 체크
    let ret = await $c.gus.cfValidate([lc_homeClsCd, lc_fixWrkPlCd, acb_inDtCls, ica_dtFrom, ica_dtTo]);
    if (!ret) {
        return; 
    }

    if (!$c.gus.cfIsAfterDate(ica_dtFrom.getValue(), ica_dtTo.getValue())) {
        await $c.win.alert(MSG_CM_ERR_039);     // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ica_dtFrom.focus();
        return;
    }

    dma_search.set("dtFrom", ica_dtFrom.getValue().substring(0,6)+"01");
    dma_search.set("dtTo", ica_dtTo.getValue());
    dma_search.set("status", "request");
    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = async function() {
    // 팝업화면에, key값인 "정비작업장코드,구매번호,선입고여부" 를 넘겨준다.
    let valueObject = {
        create: true, // 신규/상세 구분
        fixWrkPlCd: lc_fixWrkPlCd.getValue() // 정비작업장코드
    };

    const options = {
        id: "eq_420_01_07p",
        popupName: "부품구매요청등록",
        width: 1400,
        height: 600,
    };

    let result = await $c.win.openPopup("/ui/ps/eq/partmgnt/partbuyproc/eq_420_01_07p.xml", options, valueObject);

    result = "RETRIEVE";

    // 다시 조회함
    if (result === "RETRIEVE") {
        scwin.f_Retrieve();
    }
};

//-------------------------------------------------------------------------
// 상세
//-------------------------------------------------------------------------
scwin.f_Detail = async function() {
    if (ds_eq420.getRowPosition() >= 0) {
        // 팝업화면에, key값인 "정비작업장코드,구매번호,선입고여부" 를 넘겨준다.
        let valueObject = {
            create: false,  	// 신규/상세 구분
            fixWrkPlCd: ds_eq420.getCellData(ds_eq420.getRowPosition(), 'fixWrkPlCd'),  //정비작업장코드
            buyNo: ds_eq420.getCellData(ds_eq420.getRowPosition(), 'buyNo'),            //구매번호
            stsCd: ds_eq420.getCellData(ds_eq420.getRowPosition(), 'stsCd'),             //상태
            taxnCls: ds_eq420.getCellData(ds_eq420.getRowPosition(), 'taxnCls'),        //일반과세
            buyReqDt: ds_eq420.getCellData(ds_eq420.getRowPosition(), 'buyReqDt'),        //구매요청일자
            inReqDt: ds_eq420.getCellData(ds_eq420.getRowPosition(), 'inReqDt'),        //입고입고요청일자
            clntNo: ds_eq420.getCellData(ds_eq420.getRowPosition(), 'clntNo'),        //거래처코드
            clntNm: ds_eq420.getCellData(ds_eq420.getRowPosition(), 'clntNm'),        //거래처명
        };

        const options = {
            id: "eq_420_01_07p_detail",
            popupName: "부품구매요청등록",
            width: 1400,
            height: 600,
        };

        let result = await $c.win.openPopup("/ui/ps/eq/partmgnt/partbuyproc/eq_420_01_07p.xml", options, valueObject);

        result = "RETRIEVE";

        // 다시 조회함
        if (result === "RETRIEVE") {
            scwin.f_Retrieve();
        }
    } else {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_056, ["Row"]));
    }
};

//------------------------------------------------------------------------
// [작업장 콤보 조회] 소속 구분에 따른 작업장 리스트 콤보 변경 ( 조회조건 LuxCombo )
//------------------------------------------------------------------------
scwin.f_RetrieveFixWrkPl = function(homeClsCd) {
    const params = {
        sysCd: "PsCommonEBC", 
        queryId: "retriveWrkplList",
        param1: homeClsCd,
    };

    //데이터셋에 정보설정
    dma_fixWrkPl.setJSON(params);

    $c.sbm.execute(sbm_fixWrkPl);
};

//-------------------------------------------------------------------------
// 부품발주서발행
//-------------------------------------------------------------------------
scwin.f_partsOrderPublish = async function() {
    let fixWrkPlCd = "";    // 작업장코드
    let buyNo = "";         // 구매번호

    if (ds_eq420.getRowCount() === 0) {
        await $c.win.alert("조회된 내용이 없습니다.");
        return;
    }

    let printCnt = 0;
    let updateCnt = 0;
	let reportDataList = [];

	for (let i = 0; i < ds_eq420.getRowCount(); i++) {
        if (ds_eq420.getCellData(i, "chk") === "1") {
            fixWrkPlCd = ds_eq420.getCellData(i, "fixWrkPlCd");
            buyNo = ds_eq420.getCellData(i, "buyNo");

			reportDataList.push({
				odiName: "eq_420_01_06p",
                reportName: "ps/eq/fixwrkmgnt/estmgnt/eq_420_01_06p.ozr",
                odiParam : {
                    fixWrkPlCd,
                    buyNo
                },
                viewerParam : {
                    useprogressbar : false, // 프로그레스바 쓸지 말지
                },
                formParam: {}
			})

			await $c.sbm.execute(sbm_update);
            updateCnt++;
		}
	}

	if(reportDataList.length === 0){
		await $c.win.alert("선택된 내역이 없습니다.");
		return;
	}

	if(cbx_previewCheck.getValue() == 0){
		let opts = {
			type:'print', // viewer, print, download
            viewerMode:'print',
			printMode:'silent', // silent, view
		}
		await $c.ext.openBatchOzReport(reportDataList, opts);
	} else if(cbx_previewCheck.getValue() == 1 && reportDataList.length == 1){
		let opts = {
			type:'viewer', // viewer, print, download
			printMode:'silent', // silent, view
		};
		await $c.ext.openOzReport(reportDataList[0], opts);
	} else if(cbx_previewCheck.getValue() == 1 && reportDataList.length > 1){
        let opts = {
			type:'viewer', // viewer, print, download
			printMode:'silent', // silent, view
		};
		await $c.ext.openOzReport(reportDataList[0], opts);
        reportDataList.shift();

        let opts2 = {
			type:'print', // viewer, print, download
            viewerMode:'print',
			printMode:'silent', // silent, view
		}
		await $c.ext.openBatchOzReport(reportDataList, opts2);
    }

    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 조회 조건 지우기
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tb_retrieve, null);

    ed_status.setValue("request");
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {

    switch (disGubun)
  	{
  		case 1:
			// 거래처 팝업			
  			rtnList = await udc_fixClntList.cfCommonPopUp(scwin.udc_fixClntList_callBackFunc
  									,pCode					// 화면에서의 ??? Code Element의	Value
  									,pName					// 화면에서의 ??? Name Element의	Value
  									,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
  									,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
  									,null					// Title순서	
  									,null					// 보여주는 각 컬럼들의 폭	
  									,"3,4,5,6,7,8,9,10"					// 컬럼중에서 숨기는	컬럼 지정	
  									,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
  									,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
  									,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
  									,null					// 윈도우 위치 Y좌표	
  									,null					// 윈도우 위치 X좌표
  									,null					// 중복체크여부	("F")
  									,pAllSearch				// 전체검색허용여부	("F")
  									,"거래처,거래처코드,거래처명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
  									);
			break;
	}
};

scwin.udc_fixClntList_callBackFunc = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm);
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode === null || isCode === true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    }
    // inObj가 코드명 필드일 경우 팝업
    else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

//-------------------------------------------------------------------------
// 발주내역 이메일 전송.
//-------------------------------------------------------------------------
scwin.f_SendMail = async function() {
    let chk = 0;
    let chkCount = 0;
    let mailCls = "";

    for (let j = 0; j < ds_eq420.getRowCount(); j++) {
        chk = ds_eq420.getCellData(j, "chk");

        if (chk === "1") {
            mailCls = gr_eq420.getCellDisplayData(j, "emailSendDtm");



            if (mailCls === "Y") {
                if (!await $c.win.confirm(`${j + 1}행은 이미 메일이 전송되었습니다. 다시 전송하시겠습니까?`)) {
                    return;
                }
            }
            chkCount++;
        }
    }

    // 메일 전송 여부 체크
    if (chkCount === 0) {
        await $c.win.alert("메일전송 내역을 선택해 주세요.");
        return;
    } else {
        if (!await $c.win.confirm("Email을 발송하시겠습니까?")) {
            return;
        }
    }

    let mailCount = 0; // 메일 성공 카운트
    for (let i = 0; i < ds_eq420.getRowCount(); i++) {
        chk = ds_eq420.getCellData(i, "chk");

        if (chk === "1") {
            if (ds_eq420.getCellData(i, "clntEmail") == null || ds_eq420.getCellData(i, "clntEmail") == "") {
                await $c.win.alert(`${i + 1}행의 거래처 메일주소가 존재하지 않습니다.`);
                return;
            }

            if (ds_eq420.getCellData(i, "buyPicEmail") == null || ds_eq420.getCellData(i, "buyPicEmail") == "") {
                await $c.win.alert(`${i + 1}행의 담당자 메일주소가 존재하지 않습니다.`);
                return;
            }

            dma_MailCond.set("buyNo", ds_eq420.getCellData(i, "buyNo"));
            dma_MailCond.set("fixWrkPlCd", ds_eq420.getCellData(i, "fixWrkPlCd"));

            await $c.sbm.execute(sbm_retrieveMail);

            let mailContent = scwin.f_MailSet(i);
            dma_sendMail.set("cntn", rccommon.RcfReplaceContents(mailContent));

            await $c.sbm.execute(sbm_sendMail);

            mailCount++;
        }
    }

    if (mailCount === chkCount) {
        await $c.win.alert("성공적으로 메일을 전송하였습니다.");
        scwin.f_Retrieve();
    }
};

//-------------------------------------------------------------------------
// 발주내역 이메일 전송. 
//-------------------------------------------------------------------------
scwin.f_MailSet = function(row) {
	let cntn = "";
    let clntNm = ds_eq420.getCellData(row, "clntNm");
    let buyPicNm = ds_eq420.getCellData(row, "buyPicNm");
    let buyPicEmail = ds_eq420.getCellData(row, "buyPicEmail");
    let buyPicTel = ds_eq420.getCellData(row, "buyPicTel");
    let tempReqDt = ds_eq420.getCellData(row, "buyReqDt") == null ? "" : ds_eq420.getCellData(row, "buyReqDt");
    let reqDt = tempReqDt.substring(0, 4) + "." + tempReqDt.substring(4, 6) + "." + tempReqDt.substring(6, 8);
    let tempInDt = ds_eq420.getCellData(row, "inReqDt"); 
    let inDt = tempInDt.substring(0, 4) + "." + tempInDt.substring(4, 6) + "." + tempInDt.substring(6, 8);
    let telNo = ds_eq420.getCellData(row, "buyPicTel"); 

	cntn += "<table cellpadding='0' cellspacing='0' border='0' width='700'>";
	cntn += " <tr valign='top'> ";
	cntn += "  <td style='padding:5px 0 5px 15px'> ";
	cntn += "  <!-- 메일 내용 --> ";
	cntn += "  <table cellpadding='0' cellspacing='0' border='0' width='700'> ";
	cntn += "   <tr style='font-size:15px;font-weight:bold;color:#5C5C5C'> ";
	cntn += "    <td>";
	cntn += "     수  신   : "+ clntNm +"<br/>";
	cntn += "     발  신   : 동원로엑스 <br/>";
	cntn += "     발신자   : " + buyPicNm+" "+ buyPicTel +" "+ buyPicEmail+"<br/>";
	cntn += "     제  목   : 부품발주의 건<br/>";
	cntn += "     발주일   : "+reqDt+"<br/>";
	cntn += "     입고일   : "+inDt+"<br/>";
	cntn += "     결제방법 : 당사 지급 조건<br/>";
	cntn += "     입고처   : 당사 지정처";
	cntn += "    </td>";
	cntn += "   </tr>";
	cntn += "   <tr><td height='10'></td></tr>";
	cntn += "   <tr style='font-size:15px;font-weight:bold;color:#5C5C5C'>";
	cntn += "    <td>";
	cntn += "     귀사의 무궁한 발전을 기원합니다.<br/>다음과 같이 정비부품을 발주하오니, 신속히 처리하여 주시기 바랍니다.<br/>";
	cntn += "    </td>";
	cntn += "   </tr>";
	cntn += "  </table>";
	cntn += "  <table cellpadding='0' cellspacing='0' border='0' width='700'> ";
	cntn += "   <tr><td height='10'></td></tr> ";
	cntn += "   <tr><td>";
	cntn += "    <table cellpadding='5' cellspacing='0' border='0' width='650'>";
	cntn += "     <tr height='30' style='font-size:15px;font-weight:bold;color:#5C5C5C'> ";
	cntn += "      <td colspan='3' align='left'>발주금액</td> ";
	cntn += "      <td colspan='3' align='right'>( "+$c.gus.cfInsertComma(ds_eq420.getCellData(row,"supplyUpr")) +" 원)</td> ";
	cntn += "      <td align='right'>VAT별도</td> ";
	cntn += "     </tr>";
	cntn += "    </table>";
	cntn += "   </td></tr>";
	cntn += "   <tr><td> ";
	cntn += "    <table cellpadding='5' cellspacing='0' border='1' width='650'> ";
	cntn += "     <tr height='30' align='center' style='font-size:15px;font-weight:bold;color:#5C5C5C'> ";
	cntn += "      <td>부품코드</td> ";
	cntn += "      <td>부품명</td> ";
	cntn += "      <td>수량</td> ";
	cntn += "      <td>단위</td> ";
	cntn += "      <td>단가</td> ";
	cntn += "      <td>금액</td> ";
	cntn += "      <td>비고</td> ";
	cntn += "     </tr> ";

	for(let i=0; i < ds_MailContents.getRowCount(); i++){
		cntn += "     <tr height='25' style='font-size:12px;font-weight:bold;color:#5C5C5C'> ";
		cntn += "      <td align='left'>"+ds_MailContents.getCellData(i,"partCd")+"</td> ";
		cntn += "      <td align='left'>"+ds_MailContents.getCellData(i,"partNm")+"</td> ";
		cntn += "      <td align='right'>"+ds_MailContents.getCellData(i,"inQty")+"</td> ";
		cntn += "      <td align='center'>"+ds_MailContents.getCellData(i,"unitNm")+"</td> ";
		cntn += "      <td align='right'>"+$c.gus.cfInsertComma(ds_MailContents.getCellData(i,"inUpr"))+"</td> ";
		cntn += "      <td align='right'>"+$c.gus.cfInsertComma(ds_MailContents.getCellData(i,"inAmt"))+"</td> ";
